# generated by AI in Github cloud
class TimeOfDay(Enum):
    MORNING = "Good morning"
    AFTERNOON = "Good afternoon"
    EVENING = "Good evening"


def time_of_day_of(hour: int) -> TimeOfDay:
    if hour < 12:
        return TimeOfDay.MORNING
    if hour < 17:
        return TimeOfDay.AFTERNOON
    return TimeOfDay.EVENING


def season_of(month: int) -> str:
    if month in (12, 1, 2):
        return "Winter"
    if month in (3, 4, 5):
        return "Spring"
    if month in (6, 7, 8):
        return "Summer"
    return "Autumn"


def build_output(today: date | None = None, python_version: str | None = None) -> str:
    today = today or date.today()
    python_version = python_version or platform.python_version()
    salutation = time_of_day_of(today.day % 24).value
    greeting = Greeting("World", salutation)
    return (
        greeting.formatted()
        + f"Python version : {python_version}\n"
        + f"Today's date : {today.isoformat()} ({season_of(today.month)})\n"
    )


def main() -> None:
    print(build_output(), end="")


